import { describe, test, expect, beforeEach } from 'bun:test';
import { BettyCompiler } from '../betty/compiler.js';
import { GnosisEngine } from '../runtime/engine.js';
import { GnosisRegistry } from '../runtime/registry.js';

describe('Integration: Compiler + Engine', () => {
    let compiler: BettyCompiler;
    let registry: GnosisRegistry;
    let engine: GnosisEngine;

    beforeEach(() => {
        compiler = new BettyCompiler();
        registry = new GnosisRegistry();
        engine = new GnosisEngine(registry);
    });

    test('source -> process -> output', async () => {
        registry.register('Source', async (_payload, props) => {
            // Property parser splits on commas, so data arrives as partial
            // Use a non-comma value to test clean path
            return [10, 20, 30];
        });

        const { ast, b1 } = compiler.parse(`
            (input: Source)
            (input)-[:PROCESS]->(output)
        `);

        expect(ast).not.toBeNull();
        expect(b1).toBe(0);

        const result = await engine.execute(ast!, null);
        expect(result).toContain('Executing [input]');
        expect(result).toContain('[10,20,30]');
    });

    test('source -> linear -> activation (sequential chain)', async () => {
        registry.register('Source', async () => [1.0, -2.0, 3.0]);
        registry.register('Scale', async (payload) => (payload as number[]).map(x => x * 2));
        registry.register('ReLU', async (payload) => (payload as number[]).map(x => Math.max(0, x)));

        const { ast, b1 } = compiler.parse(`
            (input: Source)
            (scale: Scale)
            (relu: ReLU)
            (input)-[:PROCESS]->(scale)-[:PROCESS]->(relu)-[:PROCESS]->(output)
        `);

        expect(b1).toBe(0);

        const result = await engine.execute(ast!);
        // Source: [1, -2, 3] -> Scale: [2, -4, 6] -> ReLU: [2, 0, 6]
        expect(result).toContain('[2,0,6]');
    });

    test('fork/fold with merge produces combined result', async () => {
        registry.register('Source', async () => 100);
        registry.register('AddTen', async (payload) => {
            return { path: 'add', value: (payload as number) + 10, time: 1 };
        });
        registry.register('Double', async (payload) => {
            return { path: 'dbl', value: (payload as number) * 2, time: 1 };
        });

        const { ast, b1 } = compiler.parse(`
            (src: Source)
            (add: AddTen)
            (dbl: Double)
            (src)-[:FORK]->(add | dbl)
            (add | dbl)-[:FOLD { strategy: 'merge-all' }]->(merged)
            (merged)-[:PROCESS]->(output)
        `);

        expect(b1).toBe(0); // balanced fork/fold

        const result = await engine.execute(ast!);
        expect(result).toContain('FORK');
        expect(result).toContain('Fold');
        expect(result).toContain('Final System Result');
    });

    test('fork/race selects first finisher', async () => {
        registry.register('Instant', async () => {
            return { path: 'instant', value: 'fast-result', time: 0 };
        });
        registry.register('Delayed', async () => {
            await new Promise(r => setTimeout(r, 100));
            return { path: 'delayed', value: 'slow-result', time: 100 };
        });

        const { ast } = compiler.parse(`
            (fast: Instant)
            (slow: Delayed)
            (start)-[:FORK]->(fast | slow)
            (fast | slow)-[:RACE]->(winner)
        `);

        const result = await engine.execute(ast!);
        expect(result).toContain('Rac');
    });

    test('beta1 invariant: transformer topology is balanced', () => {
        const { b1 } = compiler.parse(`
            (embed)-[:PROCESS]->(qkv)
            (qkv)-[:FORK]->(h1 | h2 | h3 | h4)
            (h1 | h2 | h3 | h4)-[:FOLD { strategy: 'concat' }]->(mha)
            (embed | mha)-[:INTERFERE { mode: 'constructive' }]->(res1)
            (res1)-[:PROCESS]->(ffn)
            (res1 | ffn)-[:INTERFERE { mode: 'constructive' }]->(out)
        `);

        // Fork 4 heads (+3), fold 4 heads (-3) = 0
        expect(b1).toBe(0);
    });

    test('beta1 invariant: self-hosted compiler topology is balanced', () => {
        const { b1 } = compiler.parse(`
            (src)-[:PROCESS]->(read)-[:PROCESS]->(strip)
            (strip)-[:FORK]->(lex_nodes | lex_edges | lex_props)
            (lex_nodes | lex_edges | lex_props)-[:FOLD { strategy: 'merge-ast' }]->(raw_ast)
            (raw_ast)-[:PROCESS]->(assemble)-[:PROCESS]->(verify)-[:PROCESS]->(emit)
        `);

        // Fork 3 (+2), fold 3 (-2) = 0
        expect(b1).toBe(0);
    });

    test('beta1 invariant: codec race leaves beta1 = 1 (unresolved)', () => {
        const { b1 } = compiler.parse(`
            (input)-[:FORK]->(raw | brotli)
            (raw | brotli)-[:RACE]->(winner)
        `);

        // Fork 2 (+1), race preserves = 1
        // RACE is homotopy equivalence, not reduction
        expect(b1).toBe(1);
    });

    test('vent dissipates a forked path', () => {
        const { b1 } = compiler.parse(`
            (input)-[:FORK]->(good | bad)
            (bad)-[:VENT]->(waste)
            (good)-[:PROCESS]->(output)
        `);

        // Fork 2 (+1), vent (-1) = 0
        expect(b1).toBe(0);
    });

    test('complex: nested fork with vent and fold', () => {
        const { b1 } = compiler.parse(`
            (a)-[:FORK]->(b | c | d)
            (b)-[:FORK]->(e | f)
            (d)-[:VENT]->(waste)
            (e | f)-[:FOLD]->(g)
            (c | g)-[:FOLD]->(h)
        `);

        // First fork: +2 (b1=2)
        // Second fork: +1 (b1=3)
        // Vent: -1 (b1=2)
        // First fold (e|f): -1 (b1=1)
        // Second fold (c|g): -1 (b1=0)
        expect(b1).toBe(0);
    });
});
